<template>
	<view>
		<page-container :show="showMask" @afterleave="afterleave" :overlay="false"></page-container>
		<!-- pages/run/index.wxml -->
		<scroll-view scroll-x class="bg-white nav" v-if="motion_status == 0">
			<!-- <view class="flex text-center">
				<view :class="'cu-item flex-sub ' + (runType == 0 ? 'text-blue cur' : '')" @tap="tabSelect" data-id="0">жҲ·еӨ–и·‘</view>
				<view :class="'cu-item flex-sub ' + (runType == 1 ? 'text-blue cur' : '')" @tap="tabSelect" data-id="1">е®ӨеҶ…и·‘</view>
			</view> -->
		</scroll-view>
		<div>
			<!-- ж¬Ўж•°пјҡ{{ num }} еһӢеҸ·пјҡ{{ os }} -->
			<!-- жӯҘж•°пјҡ{{ runData.steps }} и°ғиҜ•йҮҢзЁӢ: {{ gps_distance | numFilter }} -->
		</div>
		<map
			id="myMap"
			v-if="runType == 0"
			:style="'width: 100%; height: ' + screenHeight + ';'"
			:show-location="false"
			:polyline="polyline"
			:latitude="latitude"
			:longitude="longitude"
			show-location
		>
			<corver-view>
				<corver-view class="cu-card article">
					<corver-view class="cu-item shadow">
						<corver-view class="flex padding-left padding-right justify-center">
							<corver-view class="text-center">
								<corver-view class="cu-bar bg-white">
									<corver-view class="action">
										<text class="cuIcon-title text-blue"></text>
										иҝҗеҠЁж—¶й—ҙ
									</corver-view>
								</corver-view>
								<corver-view class="flex margin-left text-xxl text-bold">{{ time_data }}</corver-view>
							</corver-view>
						</corver-view>
						
						<corver-view class="flex padding-left padding-right">
							<corver-view v-if="tournamentGroupDistance != null" class="flex-sub">
								<corver-view class="cu-bar bg-white">
									<corver-view class="action">
										<text class="cuIcon-title text-red"></text>
										зӣ®ж ҮйҮҢзЁӢ
									</corver-view>
								</corver-view>
								<corver-view class="flex margin-left text-xl text-bold">{{ (tournamentGroupDistance / 1000) | numFilter }} Km</corver-view>
							</corver-view>
							<corver-view v-else class="flex-sub">
								<corver-view class="cu-bar bg-white">
									<corver-view class="action">
										<text class="cuIcon-title text-red"></text>
										еҚЎи·ҜйҮҢ
									</corver-view>
								</corver-view>
								<corver-view class="flex margin-left text-xl text-bold">{{ kcal_data }} Kcal</corver-view>
							</corver-view>

							<corver-view class="flex-sub">
								<corver-view class="cu-bar bg-white">
									<corver-view class="action">
										<text class="cuIcon-title text-orange"></text>
										й…ҚйҖҹ
									</corver-view>
								</corver-view>
								<corver-view class="flex margin-left text-xl text-bold">{{ speed_data }}</corver-view>
							</corver-view>

							<corver-view class="flex-sub">
								<corver-view class="cu-bar bg-white">
									<corver-view class="action">
										<text class="cuIcon-title text-green"></text>
										йҮҢзЁӢ
									</corver-view>
								</corver-view>
								<!-- <corver-view class="flex margin-left text-xl text-bold">{{ distance_data }} Km</corver-view> -->
								<corver-view class="flex margin-left text-xl text-bold">{{ gps_distance | numFilter }} Km</corver-view>
							</corver-view>
						</corver-view>
					</corver-view>
				</corver-view>
			</corver-view>
			<corver-view style="position: fixed; width: 100%; bottom: 30px; z-index: 1024">
				<corver-view class="flex justify-center">
					<button v-if="motion_status == 0" class="cu-btn bg-green margin-left margin-right round lg" style="padding: 0 40rpx" @tap="startRun">ејҖе§Ӣи·‘жӯҘ</button>
					<!-- <button v-if="motion_status == 1" class="cu-btn bg-blue margin-left margin-right round lg" style="padding: 0 40rpx" @tap="pauseRun">жҡӮеҒңи·‘жӯҘ</button> -->
					<!-- <button v-if="motion_status == 2" class="cu-btn bg-orange margin-left margin-right round lg" style="padding: 0 40rpx" @tap="reRun">жҒўеӨҚи·‘жӯҘ</button> -->
					<button v-if="motion_status == 1 || motion_status == 2" class="cu-btn bg-red margin-left margin-right round lg" style="padding: 0 40rpx" @longpress="stopRun">
						й•ҝжҢүеҒңжӯў
					</button>
				</corver-view>
			</corver-view>
		</map>
	</view>
</template>

<script>
// pages/run/index.js
import timer from '@/utils/lebu-timer';
import lebu from '@/utils/lebu-core';
import { runInfoAdd, runInfoExtendAdd } from '@/api/runInfo.js';
import { tournamentGroupInfo, tournamentAdd } from '@/api/tournament.js';
import { difference, add } from '@/utils/calculate_time.js';
import runCore from '@/utils/run_core';
export default {
	data() {
		return {
			num: 0,
			num2: 0,
			os: uni.getSystemInfoSync().osName,
			screenHeight: 0,

			polyline: [
				{
					points: [],
					color: '#07c160',
					width: 2
				}
			],

			latitude: 0,
			longitude: 0,
			altitude_data: [],
			time_data: '00:00:00',
			kcal_data: '0.00',
			speed_data: '0\'00"',
			distance_data: '0.00',
			motion_status: 0,
			time_id: 0,
			points_time: parseInt(Date.now() / 1000),
			km_speed_data: [],
			km_distance_data: 0,
			runType: 0,
			altitude: '',
			backButtonPress: 0,
			showMask: false,
			runTime: null,
			runData: {
				steps: 0
			},
			gps_distance: 0,
			oldSteps: 0,
			startRunTime: null,//ејҖе§Ӣи·‘жӯҘж—¶й—ҙ
			tournamentGroupId: null, // жҜ”иөӣеҲҶз»„id
			tournamentGroupDistance: null, // жҜ”иөӣеҲҶз»„и·қзҰ»
		};
	},
	/**
	 * з”ҹе‘Ҫе‘ЁжңҹеҮҪж•°--зӣ‘еҗ¬йЎөйқўеҠ иҪҪ
	 */ onLoad: function(options) {
		 if(options.tournamentGroupId != null){
			this.tournamentGroupId = options.tournamentGroupId;
			tournamentGroupInfo(this.tournamentGroupId).then(res => {
				this.tournamentGroupDistance = res.data.distance;
				console.log(this.tournamentGroupDistance)
			})
		 }
	 },
	/**
	 * з”ҹе‘Ҫе‘ЁжңҹеҮҪж•°--зӣ‘еҗ¬йЎөйқўеҲқж¬ЎжёІжҹ“е®ҢжҲҗ
	 */
	onReady: function() {
		this.setScreenHeight();
		this.initRun();
	},
	/**
	 * з”ҹе‘Ҫе‘ЁжңҹеҮҪж•°--зӣ‘еҗ¬йЎөйқўжҳҫзӨә
	 */
	onShow: function() {
		console.log('AppжҳҫзӨә' + this.motion_status + this.runTime);
		this.checkLocation();
		if (this.motion_status == 1 && this.runTime != null) {
			console.log('еӨ„зҗҶж—¶й—ҙ');
			timer.restore(this.runTime, new Date());
			this.refreshShowTime();
		}
	},
	onHide: function() {
		console.log('йҡҗи—ҸApp');
		if (this.motion_status == 1) {
			// и®°еҪ•йҡҗи—ҸAppејҖе§Ӣж—¶й—ҙ
			this.runTime = new Date();
		}
		console.log('и®°еҪ•ж—¶й—ҙ' + this.runTime);
		timer.end();
		this.stopRefreshShowTime();
	},
	/**
	 * з”ҹе‘Ҫе‘ЁжңҹеҮҪж•°--зӣ‘еҗ¬йЎөйқўеҚёиҪҪ
	 */
	onUnload: function() {
		this.stopRefreshShowTime();
		let that = this;

		//ж—¶й—ҙи®Ўж•°еҷЁйҮҚзҪ®
		timer.end();
		timer.reset();

		//е®ҡдҪҚеҒңжӯў
		if (this.runType == 0) {
			uni.stopLocationUpdate({
				complete: res => {}
			});
		}
		//еҠ йҖҹеәҰдј ж„ҹеҷЁеҒңжӯўзӣ‘жөӢ
		uni.offAccelerometerChange(this.calculateAccelerometer);
		this.motion_status = 2;
		uni.stopAccelerometer();
		runCore.reset();
	},
	filters: {
		/**
		 * жҲӘеҸ–дёӨдҪҚиҝҮж»ӨеҷЁ
		 * @param {Object} value
		 */
		numFilter(value) {
			// жҲӘеҸ–еҪ“еүҚж•°жҚ®еҲ°е°Ҹж•°зӮ№еҗҺдёӨдҪҚ
			let realVal = parseFloat(value).toFixed(2);
			return realVal;
		}
	},
	methods: {
		/**
		 * з§»еҠЁең°еӣҫ
		 * @param {Object} latitude зә¬еәҰ
		 * @param {Object} longitude з»ҸеәҰ
		 */
		getMap(latitude, longitude) {
			this.latitude = latitude;
			this.longitude = longitude;
			let obj = uni.createMapContext('myMap');
			obj.moveToLocation({
				//moveToLocationе°Ҷең°еӣҫдёӯеҝғз§»еҠЁеҲ°еҪ“еүҚе®ҡдҪҚзӮ№пјҢйңҖиҰҒй…ҚеҗҲmapз»„д»¶зҡ„show-locationдҪҝз”Ё
				latitude: latitude,
				longitude: longitude
			});
		},

		tabSelect(e) {
			this.setData({
				runType: e.currentTarget.dataset.id
			});
		},

		initRun() {
			let that = this;
			if (this.runType == 0) {
				uni.getLocation({
					altitude: true,
					success(res) {
						that.setData({
							latitude: res.latitude,
							longitude: res.longitude,
							altitude: res.altitude
						});
						setTimeout(function() {
							let obj = uni.createMapContext('myMap');
							obj.moveToLocation();
						}, 1000);
					},
					fail() {
						that.checkLocation();
					}
				});
			}
		},
		/**
		 * ејҖе§Ӣи·‘жӯҘ
		 */
		startRun() {
			timer.start();
			this.startRunTime = parseInt(Date.now() / 1000);
			
			this.refreshShowTime();

			let that = this;
			this.vibrateFunc(1);
			this.showMask = true;
			uni.showModal({
				title: 'жҸҗзӨә',
				content: 'е°ҶжүӢжңәж”ҫзҪ®еңЁиЈӨиўӢеҪ“дёӯжҲ–жҠ“зқҖжүӢжңәж‘ҶиҮӮи·‘жӯҘ,еҸҜд»ҘиҺ·еҫ—жӣҙеҠ зІҫеҮҶзҡ„ж•°жҚ®з»ҹи®Ўе“Ұ!',
				showCancel: false
			});
			if (this.runType == 0) {
				uni.startLocationUpdateBackground({
					success: res => {
						uni.onLocationChange(this.locationChange);
					},
					fail: res => {
						// console.log(res);
					}
				});
			}

			this.motion_status = 1;

			uni.startAccelerometer({
				interval: 'game',
				success() {
					uni.onAccelerometerChange(that.calculateAccelerometer);
				}
			});
		},
		/**
		 * жҡӮеҒңи·‘жӯҘ
		 */
		pauseRun() {
			this.runTime = null;
			timer.end();
			this.stopRefreshShowTime();

			this.vibrateFunc(1);
			let that = this;

			if (this.runType == 0) {
				uni.stopLocationUpdate({
					complete: res => {}
				});
			}
			wx.stopAccelerometer();
			// uni.offAccelerometerChange(this.calculateAccelerometer);
			this.motion_status = 2;
		},
		/**
		 * жҒўеӨҚи·‘жӯҘ
		 */
		reRun() {
			this.refreshShowTime();
			timer.start();
			this.vibrateFunc(1);

			let that = this;
			if (this.runType == 0) {
				uni.startLocationUpdateBackground({
					success: res => {
						uni.onLocationChange(that.locationChange);
					},
					fail: res => {}
				});
			}
			this.motion_status = 1;
			wx.startAccelerometer({
				interval: 'game',
				success() {
					uni.onAccelerometerChange(that.calculateAccelerometer);
				}
			});
		},
		/**
		 * з»“жқҹи·‘жӯҘ
		 */
		stopRun() {
			timer.end();

			this.vibrateFunc(2);
			let that = this;

			if (this.runType == 0) {
				uni.stopLocationUpdate({
					complete: res => {}
				});
			}
			wx.stopAccelerometer();
			// uni.offAccelerometerChange(this.calculateAccelerometer);
			this.motion_status = 2;
			
			if (this.gps_distance == 0) {
				uni.showModal({
					title: 'жңӘжЈҖжөӢеҲ°д»»дҪ•з§»еҠЁ',
					content: 'з»§з»ӯиҝҗеҠЁиҝҳжҳҜиҲҚејғиҝҷжқЎи®°еҪ•?',
					cancelText: 'иҲҚејғ',
					confirmText: 'з»§з»ӯ',

					success(res) {
						if (res.confirm) {
							that.reRun();
						} else {
							timer.reset();
							uni.switchTab({
								url: '/pages/index/index'
							});
						}
					}
				});
			} else if (this.gps_distance < 0.1) {
				uni.showModal({
					title: 'з§»еҠЁи·қзҰ»еӨӘзҹӯ',
					content: 'з»§з»ӯиҝҗеҠЁиҝҳжҳҜиҲҚејғиҝҷжқЎи®°еҪ•?',
					cancelText: 'иҲҚејғ',
					confirmText: 'з»§з»ӯ',

					success(res) {
						if (res.confirm) {
							that.reRun();
						} else {
							timer.reset();
							uni.switchTab({
								url: '/pages/index/index'
							});
						}
					}
				});
			} else if (this.tournamentGroupDistance != null && this.gps_distance < (this.tournamentGroupDistance / 1000)){
				uni.showModal({
					title: 'жңӘиҫҫеҲ°зӣ®ж Үи·қзҰ»',
					content: 'з»§з»ӯиҝҗеҠЁиҝҳжҳҜиҲҚејғжң¬ж¬ЎжҜ”иөӣи®°еҪ•?',
					cancelText: 'иҲҚејғ',
					confirmText: 'з»§з»ӯ',
				
					success(res) {
						if (res.confirm) {
							that.reRun();
						} else {
							timer.reset();
							uni.switchTab({
								url: '/pages/index/index'
							});
						}
					}
				});
			} else {
				this.stopRefreshShowTime();

				// еӨ„зҗҶstringиҪ¬Long
				var distanceDataNum = new Number(parseFloat(this.gps_distance).toFixed(2));
				var kcalDataNum = new Number(this.kcal_data);

				uni.showLoading({
					title: 'жӯЈеңЁдҝқеӯҳи®°еҪ•',
					mask: true
				});
				
				
				if(this.tournamentGroupId != null){
					this.saveTournamentRunInfo(distanceDataNum, kcalDataNum)
				}else{
					let then = this;
					// дҝқеӯҳж•°жҚ®иҮіж•°жҚ®еә“
					runInfoAdd({
						time: this.time_data,
						speed: this.speed_data,
						kcal: kcalDataNum * 1000,
						distance: distanceDataNum * 1000,
						kmSpeed: JSON.stringify(this.km_speed_data),
						points: JSON.stringify(this.polyline[0].points),
						altitude: JSON.stringify(this.altitude_data),
						altitudeSum: this.altitude,
						runType: this.runType,
						step: this.runData.steps,
						startRunTime: this.startRunTime,
						endRunTime: parseInt(Date.now() / 1000),
					}).then(res => {
						runInfoExtendAdd({
							runInfoId: res.data,
							accelerometer: JSON.stringify(then.accelerometer)
						});
						// lebu.reset();
						uni.hideLoading();
						uni.redirectTo({
							url: './statement?id=' + res.data
						});
					});
				}
			}
		},
		
		/**
		 * дҝқеӯҳжҜ”иөӣи·‘жӯҘж•°жҚ®
		 * @param {Object} distanceDataNum
		 * @param {Object} kcalDataNum
		 */
		saveTournamentRunInfo(distanceDataNum, kcalDataNum) {
			let then = this;
			// дҝқеӯҳж•°жҚ®иҮіж•°жҚ®еә“
			tournamentAdd({
				time: this.time_data,
				speed: this.speed_data,
				kcal: kcalDataNum * 1000,
				distance: distanceDataNum * 1000,
				kmSpeed: JSON.stringify(this.km_speed_data),
				points: JSON.stringify(this.polyline[0].points),
				altitude: JSON.stringify(this.altitude_data),
				altitudeSum: this.altitude,
				runType: this.runType,
				step: this.runData.steps,
				startRunTime: this.startRunTime,
				endRunTime: parseInt(Date.now() / 1000),
				tournamentGroupId: this.tournamentGroupId
			}).then(res => {
				uni.hideLoading();
				uni.redirectTo({
					url: './statement_tournament?id=' + res.data
				});
			});
		},

		/**
		 * жүӢжңәйңҮеҠЁ
		 * @param {Object} mode
		 */
		vibrateFunc(mode) {
			if (uni.getStorageSync('vibrate')) {
				if (mode == 1) {
					uni.vibrateShort({
						complete: res => {}
					});
				}

				if (mode == 2) {
					uni.vibrateLong({
						complete: res => {}
					});
				}
			}
		},

		//и®ҫе®ҡең°еӣҫй«ҳеәҰдёәе…ЁеұҸе№•й«ҳеәҰ
		setScreenHeight() {
			let that = this;
			uni.getSystemInfo({
				success: res => {
					that.setData({
						screenHeight: res.screenHeight * 0.901 + 'px'
					});
				}
			});
		},

		//жЈҖжөӢжҳҜеҗҰејҖеҗҜеҗҺеҸ°е®ҡдҪҚ,е№¶еј•еҜјз”ЁжҲ·ејҖеҗҜ
		checkLocation() {
			if (this.runType == 1) {
				return;
			}
			if (uni.getSystemInfoSync().hostName == 'WeChat') {
				uni.getSetting({
					success(res) {
						let ulb = res.authSetting['scope.userLocationBackground']; //console.log(res.authSetting)

						if (ulb == false || ulb == undefined || res.authSetting['scope.userLocation'] == false) {
							uni.showModal({
								title: 'жҸҗзӨә',
								content: 'иҜ·е…Ҳи®ҫзҪ®дҪҚзҪ®дҝЎжҒҜдёә"дҪҝз”Ёе°ҸзЁӢеәҸжңҹй—ҙе’ҢзҰ»ејҖе°ҸзЁӢеәҸеҗҺ",жүҚеҸҜиҝҗиЎҢи·‘жӯҘжЁЎеқ—',

								success(res) {
									if (res.confirm) {
										uni.openSetting({});
									} else {
										uni.switchTab({
											url: '../index/index'
										});
									}
								}
							});
						}
					}
				});
			}
		},

		checkDistance(lat2, lng2, cur_time) {
			let obj = this.polyline[0].points[this.polyline[0].points.length - 1]; // console.log(this.data.polyline[0].points);

			let lat1 = obj.latitude;
			let lng1 = obj.longitude; // и°ғз”Ё returnзҡ„и·қзҰ»еҚ•дҪҚдёәm

			let radLat1 = (lat1 * Math.PI) / 180;
			let radLat2 = (lat2 * Math.PI) / 180;
			let a = radLat1 - radLat2;
			let b = (lng1 * Math.PI) / 180 - (lng2 * Math.PI) / 180;
			let s = 2 * Math.asin(Math.sqrt(Math.pow(Math.sin(a / 2), 2) + Math.cos(radLat1) * Math.cos(radLat2) * Math.pow(Math.sin(b / 2), 2)));
			s = s * 6378.137; // EARTH_RADIUS;

			s = Math.round(s * 10000) / 10; //m
			
			// иҝҮж»ӨеҗҢдёҖз§’ж•°жҚ®
			let time_differece = cur_time - this.points_time; //з§’
			if (time_differece <= 0) {
				return false;
			}
			this.points_time = cur_time;
			
			
			// let cal_distance = (lebu.getStride() / 100) * time_differece; //cm => m
			// let cal_distance = (runCore.getStride() / 100) * time_differece; //cm => m
			// if (this.oldSteps != this.runData.steps) {
			// 	this.oldSteps = this.runData.steps;
			// 	this.gps_distance = this.gps_distance + s / 1000;
			// }

			// if ((s <= cal_distance && s > 0) || (s <= this.distance_data && this.distance > 0) || (s < 35 && s > 0)) {
			if ((this.oldSteps != this.runData.steps) && (s < 300 && s > 0)) {
				this.oldSteps = this.runData.steps;
				this.gps_distance = this.gps_distance + s / 1000;
				return true;
			} else {
				return false;
			}
		},

		/**
		 * жӢҰжҲӘйЎөйқўиҝ”еӣһдәӢд»¶
		 */
		afterleave() {
			if (this.motion_status == 1 || this.motion_status == 2) {
				this.backButtonPress++;
				if (this.backButtonPress < 2) {
					uni.showToast({
						icon: 'none',
						title: 'еҶҚжҢүдёҖж¬ЎйҖҖеҮәи·‘жӯҘ',
						duration: 1000
					});
				}
				this.showMask = false;
				let that = this;
				setTimeout(function() {
					that.backButtonPress = 0;
					that.showMask = true;
				}, 2000);
			}
			return false;
		},
		locationChange(result) {
			// console.log('дҪҚзҪ®еҸҳеҢ–дәҶ');
			let points = this.polyline[0].points; //жЈҖжөӢи·қзҰ»

			if (this.polyline[0].points.length == 0 || this.checkDistance(result.latitude, result.longitude, parseInt(Date.now() / 1000))) {
				points.push({
					longitude: result.longitude,
					latitude: result.latitude
				});
				this.polyline[0].points = points;
				this.setData({
					longitude: result.longitude,
					latitude: result.latitude
				});
				this.getMap(result.latitude, result.longitude);
			}
		},
		// ејҖе§ӢеҲ·ж–°йЎөйқўж—¶й—ҙ
		refreshShowTime() {
			this.stopRefreshShowTime();
			let that = this;
			this.time_id = setInterval(function() {
				// console.log('и§ҰеҸ‘setInterval');
				let time_data = timer.getTime();
				// console.log('еұ•зӨәж—¶й—ҙ' + time_data);
				that.setData({
					time_data: time_data
				});
			}, 1000);
		},
		// жҡӮеҒңеҲ·ж–°йЎөйқўж—¶й—ҙ
		stopRefreshShowTime() {
			clearInterval(this.time_id);
		},
		/**
		 * и®Ўз®—еҠ йҖҹи®Ўж•°жҚ®
		 */
		calculateAccelerometer(res) {
			this.num2++;
			// if (uni.getSystemInfoSync().hostName == 'WeChat' && uni.getSystemInfoSync().osName != 'ios' && this.num2 % 10 != 0) {
			// 	return;
			// }
			this.num++;
			let run_data = runCore.getAcceleration(res, this.time_data, this.gps_distance);
			this.runData = run_data;
			this.setData({
				distance_data: run_data.distance,
				kcal_data: run_data.kcal,
				speed_data: run_data.speed
			});

			if (run_data.distance - this.km_distance_data >= 1) {
				let km_speed_obj = this.km_speed_data;
				km_speed_obj.push(run_data.speed);
				let altitude_obj = this.altitude_data;
				altitude_obj.push(this.altitude);
				this.setData({
					km_distance_data: run_data.distance,
					km_speed_data: km_speed_obj,
					altitude_data: altitude_obj
				});
			}
		}
	}
};
</script>
